function getCrafterToken(crafter) {
  const e = process.env;
  if (["후제","무통","앙리자이에","그로"].includes(crafter))        return e["TG_" + "TOKEN_HOOJE"];
  if (["메오","돔페리뇽","오베르"].includes(crafter))               return e["TG_" + "TOKEN_MEO"];
  if (crafter === "포므리")                                          return e["TG_" + "TOKEN_POMMERY"];
  if (crafter === "뒤작")                                            return e["TG_" + "TOKEN_DUIJAC"];
  if (crafter === "디켐")                                            return e["TG_" + "TOKEN_DIKEM"];
  if (crafter === "크뤼그")                                          return e["TG_" + "TOKEN_KRUG"];
  if (crafter === "아르망")                                          return e["TG_" + "TOKEN_ARMAND"];
  if (["라피트","장테","르루아"].includes(crafter))                  return e["TG_" + "TOKEN_LAPIT"];
  return null;
}

