function isRateLimited(item, ip) {
  const now = Date.now();
  const last = lastItemSent.get(item) || 0;
  if (now - last < 30 * 1000) return true;
  const hits = (ipHits.get(ip) || []).filter(t => now - t < 60 * 1000);
  if (hits.length >= 5) return true;
  hits.push(now);
  ipHits.set(ip, hits);
  lastItemSent.set(item, now);
  return false;
}

// Netlify가 쿼리스트링을 1차 디코딩하므로 추가 디코딩은 %xx 패턴이 남아있을 때만 (malformed % 입력 시 500 방지)
function safeDecode(s) {
  if (!/%[0-9A-Fa-f]{2}/.test(s)) return s;
  try { return decodeURIComponent(s); } catch { return s; }
}

// ── 실시간 제작자 조회 (Firebase items) — 안전장치: 성공만 캐시 / 타임아웃 / 폴백 ──
const ITEMS_URL = `${RTDB_URL}/items.json`;
const ITEMS_TTL = 60 * 1000;          // 인스턴스 메모리 캐시 수명(ms)
const ITEMS_FETCH_TIMEOUT = 3000;     // Firebase 읽기 타임아웃(ms)
let _itemsCache = null;               // { maps: {full, short}, at: number } — 성공 응답만 보관

const stripBracket = (name) => String(name).replace(/^\[.*?\]\s*/, "");

// items.json(카테고리 → id → {name, crafter}) → { full:{이름:제작자}, short:{단축명:제작자} }
function buildLiveMap(itemsData) {
  if (!itemsData || typeof itemsData !== "object") return null;
  const full = {}, short = {};
  for (const catKey of Object.keys(itemsData)) {
    const grp = itemsData[catKey];
    if (!grp || typeof grp !== "object") continue;
    for (const id of Object.keys(grp)) {
      const it = grp[id];
      if (!it || !it.name || !it.crafter) continue;   // 이름/제작자 누락(빈칸)은 스킵
      full[it.name] = it.crafter;
      short[stripBracket(it.name)] = it.crafter;
    }
  }
  return Object.keys(full).length ? { full, short } : null;  // 빈 결과는 무효 처리
}

async function getLiveMap() {
  const now = Date.now();
  if (_itemsCache && now - _itemsCache.at < ITEMS_TTL) return _itemsCache.maps;
  try {
    const ctrl = new AbortController();
    const timer = setTimeout(() => ctrl.abort(), ITEMS_FETCH_TIMEOUT);
    const res = await fetch(ITEMS_URL, { signal: ctrl.signal });
    clearTimeout(timer);
    if (!res.ok) return _itemsCache ? _itemsCache.maps : null;
    const maps = buildLiveMap(await res.json());
    if (maps) { _itemsCache = { maps, at: now }; return maps; }  // 성공 + 비어있지 않을 때만 캐시
    return _itemsCache ? _itemsCache.maps : null;                // 빈/이상 응답: 캐시 오염 금지
  } catch (e) {
    return _itemsCache ? _itemsCache.maps : null;                // 읽기 실패/타임아웃: 캐시 오염 금지
  }
}

// 제작자 결정: 실시간(전체명→단축명) 우선, 단 '토큰 보유' 시에만. 아니면 고정맵 폴백.
function resolveCrafter(liveMaps, fullItem, shortItem) {
  const baked = ITEM_TO_CRAFTER[shortItem] || ITEM_TO_CRAFTER[fullItem] || null;
  const live  = liveMaps ? (liveMaps.full[fullItem] || liveMaps.short[shortItem] || null) : null;
  if (live && getCrafterToken(live)) return live;     // 실시간 값 + 토큰 OK → 실시간 우선
  if (baked && getCrafterToken(baked)) return baked;  // 토큰 없는 실시간/실시간 없음 → 고정맵
  return baked || live || null;                       // 최후: 있는 값이라도 반환
}

// RTDB 카운터 원자적 +1 (ETag compare-and-swap, 재시도) — 7일 정리와 무관한 영구 카운터
async function incrStat(path) {
  const url = `${RTDB_URL}/${path}.json`;
  for (let i = 0; i < 5; i++) {
    const getRes = await fetch(url, { headers: { "X-Firebase-ETag": "true" } });
    const etag = getRes.headers.get("ETag");
    let cur = await getRes.json();
    cur = typeof cur === "number" ? cur : 0;
    const putRes = await fetch(url, {
      method: "PUT",
      headers: { "Content-Type": "application/json", "if-match": etag },
      body: JSON.stringify(cur + 1),
    });
    if (putRes.ok) return cur + 1;
    if (putRes.status !== 412) return null; // 412=ETag 불일치 → 재시도
  }
  return null;
}

exports.handler = async (event) => {
  const jsonHeaders = {
    "Access-Control-Allow-Origin": "*",
    "Content-Type": "application/json; charset=utf-8",
  };

  const params = event.queryStringParameters || {};
  const rawItem = params.item || "";
  const fullItem = safeDecode(rawItem).trim();  // 전체 아이템명 (브라켓 포함 가능)

  if (!fullItem) {
    return { statusCode: 400, headers: jsonHeaders, body: JSON.stringify({ ok: false, error: "item 파라미터가 없습니다." }) };
  }

  const clientIp = (event.headers && (event.headers["x-nf-client-connection-ip"] || event.headers["client-ip"])) || "unknown";
  if (isRateLimited(fullItem, clientIp)) {
    return { statusCode: 429, headers: jsonHeaders, body: JSON.stringify({ ok: false, error: "요청이 너무 잦습니다. 잠시 후 다시 시도해주세요." }) };
  }

  // 브라켓 prefix 제거 후 제작자 결정 (실시간 Firebase 우선 + 고정맵 폴백)
  const shortItem = stripBracket(fullItem);
  const liveMaps = await getLiveMap();
  const crafter = resolveCrafter(liveMaps, fullItem, shortItem);

  if (!crafter) {
    return { statusCode: 200, headers: jsonHeaders, body: JSON.stringify({ ok: false, error: `'${shortItem}' 은(는) DB에 없습니다.` }) };
  }

  const token  = getCrafterToken(crafter);
  const chatId = process.env["TG_" + "CHAT_ID"];

  if (!token || !chatId) {
    return { statusCode: 500, headers: jsonHeaders, body: JSON.stringify({ ok: false, error: "서버 환경변수 누락" }) };
  }

  // 주문 경로 (웹사이트 src=web / 그 외는 애드온 URL 경유)
  const orderSource = params.src === "web" ? "web" : "addon";
  const sourceLabel = orderSource === "web" ? "Web" : "AddOn";

  // 텔레그램 메시지 — 2줄 (아이템 줄 끝에 경로 표시)
  const itemLine = fullItem + " via " + sourceLabel;
  const message = "제작자: " + crafter + "\n아이템: " + itemLine;

  try {
    // 1. 텔레그램 전송
    const tgRes = await fetch(
      `https://api.telegram.org/bot${token}/sendMessage`,
      {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ chat_id: chatId, text: message }),
      }
    );
    const tgData = await tgRes.json();
    if (!tgData.ok) {
      return { statusCode: 502, headers: jsonHeaders, body: JSON.stringify({ ok: false, error: "텔레그램 전송 실패", detail: tgData }) };
    }

    // 2. Firebase /orders 기록 — 애드온/직접 호출도 Live Orders에 표시되도록
    //    (웹사이트 주문은 클라이언트가 직접 기록하므로 src=web 이면 건너뜀)
    //    생성된 주문 키는 리디렉션 URL(&o=)로 전달되어 '나의 주문' 추적에 사용됨
    let orderKey = null;
    if (params.src !== "web") {
      try {
        const dupRes = await fetch(`${RTDB_URL}/orders.json?orderBy="$key"&limitToLast=20`);
        const recent = (await dupRes.json()) || {};
        const now = Date.now();
        const dupEntry = Object.entries(recent).find(
          ([, o]) => o && o.itemName === fullItem && o.timestamp && now - o.timestamp < 90 * 1000
        );
        if (dupEntry) {
          // 90초 내 동일 아이템 주문 존재 → 기존 주문 키에 연결
          orderKey = dupEntry[0];
        } else {
          const postRes = await fetch(`${RTDB_URL}/orders.json`, {
            method: "POST",
            headers: { "Content-Type": "application/json" },
            body: JSON.stringify({ crafter, itemName: fullItem, status: "pending", source: "addon", timestamp: { ".sv": "timestamp" } }),
          });
          const postData = await postRes.json();
          if (postData && postData.name) {
            orderKey = postData.name;
            // 주문 카운터 +1 (영구 누적 + 현재 시즌). 중복 주문은 위 dupEntry로 걸러져 여기 안 옴
            try {
              let seasonKey = "midnight_s1";
              try {
                // 시즌 목록에서 '지금 기준 가장 최근에 시작된(해당일 오전8시 KST) 시즌' 파생
                const seasons = await (await fetch(`${RTDB_URL}/stats/seasons.json`)).json();
                if (seasons && typeof seasons === "object") {
                  const arr = Object.entries(seasons)
                    .map(([id, v]) => ({ id, start: v && v.start }))
                    .filter((x) => /^\d{4}-\d{2}-\d{2}$/.test(x.start))
                    .sort((a, b) => (a.start < b.start ? -1 : a.start > b.start ? 1 : 0));
                  const nowMs = Date.now();
                  let cur = null;
                  for (const sn of arr) {
                    if (Date.parse(sn.start + "T08:00:00+09:00") <= nowMs) cur = sn; else break;
                  }
                  if (cur) seasonKey = cur.id;
                }
              } catch (e2) {}
              await incrStat("stats/orders_total");
              await incrStat("stats/season/" + seasonKey);
              const _d = new Date(Date.now() + 9 * 3600 * 1000).toISOString().slice(0, 10);
              const _sk = (x) => String(x).replace(/[.#$\[\]\/]/g, "_");
              await incrStat("stats/orders_daily/" + _d + "/t");
              await incrStat("stats/orders_daily/" + _d + "/c/" + _sk(crafter));
            } catch (e3) {}
          }
        }
      } catch (e) {
        // 기록 실패해도 알림 흐름은 유지
      }
    }

    // 3. 성공 → hooje.pro로 리디렉션 (HTML meta-refresh)
    const redirectUrl = `https://hooje.pro/?notified=1&c=${encodeURIComponent(crafter)}&i=${encodeURIComponent(fullItem)}`
      + (orderKey ? `&o=${encodeURIComponent(orderKey)}` : "");
    return {
      statusCode: 200,
      headers: { "Content-Type": "text/html; charset=utf-8" },
      body: `<!DOCTYPE html><html><head>
<meta http-equiv="refresh" content="0;url=${redirectUrl}">
<script>window.location.replace(${JSON.stringify(redirectUrl)});</script>
</head><body></body></html>`,
    };
  } catch (err) {
    return { statusCode: 500, headers: jsonHeaders, body: JSON.stringify({ ok: false, error: err.message }) };
  }
};

// 로컬 시뮬레이션/검증 전용 export (Netlify 런타임 동작에는 영향 없음)
module.exports._test = { buildLiveMap, getLiveMap, resolveCrafter, getCrafterToken, stripBracket, ITEM_TO_CRAFTER };
